import React, { useState, useEffect } from 'react';
import { getUserBorrows, returnBook, getUserWaitingList } from '../api/api';

function MyBorrows({ currentUserId }) {
  const [borrowRecords, setBorrowRecords] = useState([]);
  const [waitlistEntries, setWaitlistEntries] = useState([]);
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState({ text: '', isError: false });

  const fetchData = async () => {
    setLoading(true);
    try {
      const borrowRes = await getUserBorrows(currentUserId);
      setBorrowRecords(borrowRes.data);

      const waitlistRes = await getUserWaitingList(currentUserId);
      setWaitlistEntries(waitlistRes.data);
    } catch (error) {
      console.error("Error fetching user data:", error);
      showMessage("Failed to load user borrow history and waitlist.", true);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, [currentUserId]);

  const showMessage = (text, isError = false) => {
    setMessage({ text, isError });
    setTimeout(() => setMessage({ text: '', isError: false }), 5000);
  };

  const handleReturn = async (recordId, title) => {
    try {
      const res = await returnBook(recordId);
      const returnedRecord = res.data;
      if (returnedRecord.fineAmount > 0) {
        showMessage(`Successfully returned '${title}'! Note: You incurred an overdue fine of ₹${returnedRecord.fineAmount.toFixed(2)}.`, false);
      } else {
        showMessage(`Successfully returned '${title}'!`, false);
      }
      fetchData();
    } catch (error) {
      const errMsg = error.response?.data?.error || "Failed to return book.";
      showMessage(errMsg, true);
    }
  };

  const getStatusBadge = (status) => {
    switch (status) {
      case 'BORROWED':
        return <span className="badge badge-info">Borrowed</span>;
      case 'OVERDUE':
        return <span className="badge badge-danger">Overdue</span>;
      case 'RETURNED':
        return <span className="badge badge-success">Returned</span>;
      default:
        return <span className="badge">{status}</span>;
    }
  };

  const getWaitlistStatusBadge = (status) => {
    switch (status) {
      case 'WAITING':
        return <span className="badge badge-warning">Waiting in Queue</span>;
      case 'NOTIFIED':
        return <span className="badge badge-success">Ready to Claim</span>;
      default:
        return <span className="badge">{status}</span>;
    }
  };

  return (
    <div className="page">
      <div className="page-header">
        <h2>My Borrowed Books</h2>
        <span>Active User ID: <strong>{currentUserId}</strong></span>
      </div>

      {message.text && (
        <div className={`alert-box ${message.isError ? 'alert-error' : 'alert-success'}`}>
          {message.text}
        </div>
      )}

      {loading ? (
        <p>Loading history...</p>
      ) : (
        <>
          <h3>Current Borrows & History</h3>
          {borrowRecords.length === 0 ? (
            <p>You have not borrowed any books yet.</p>
          ) : (
            <table>
              <thead>
                <tr>
                  <th>Book Title</th>
                  <th>Borrow Date</th>
                  <th>Due Date</th>
                  <th>Return Date</th>
                  <th>Fine</th>
                  <th>Status</th>
                  <th>Action</th>
                </tr>
              </thead>
              <tbody>
                {borrowRecords.map((record) => (
                  <tr key={record.id}>
                    <td><strong>{record.bookTitle}</strong></td>
                    <td>{record.borrowDate}</td>
                    <td>{record.dueDate}</td>
                    <td>{record.returnDate || '-'}</td>
                    <td>
                      {record.fineAmount > 0 ? (
                        <strong style={{ color: '#e74c3c' }}>₹{record.fineAmount.toFixed(2)}</strong>
                      ) : (
                        '₹0.00'
                      )}
                    </td>
                    <td>{getStatusBadge(record.status)}</td>
                    <td>
                      {(record.status === 'BORROWED' || record.status === 'OVERDUE') && (
                        <button
                          className="btn btn-primary btn-sm"
                          onClick={() => handleReturn(record.id, record.bookTitle)}
                        >
                          Return Book
                        </button>
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}

          <h3 style={{ marginTop: '40px' }}>Active Waiting List Queue</h3>
          {waitlistEntries.length === 0 ? (
            <p>You are not currently in any waiting list.</p>
          ) : (
            <table>
              <thead>
                <tr>
                  <th>Book Title</th>
                  <th>Position</th>
                  <th>Status</th>
                  <th>Deadline (if notified)</th>
                  <th>Action</th>
                </tr>
              </thead>
              <tbody>
                {waitlistEntries.map((entry) => (
                  <tr key={entry.id}>
                    <td><strong>{entry.bookTitle}</strong></td>
                    <td>
                      {entry.status === 'NOTIFIED' ? (
                        <span style={{ color: '#2ecc71', fontWeight: 'bold' }}>First (Next in Line)</span>
                      ) : (
                        <span>Position #{entry.queuePosition}</span>
                      )}
                    </td>
                    <td>{getWaitlistStatusBadge(entry.status)}</td>
                    <td>
                      {entry.claimDeadline
                        ? new Date(entry.claimDeadline).toLocaleString()
                        : '-'}
                    </td>
                    <td>
                      {entry.status === 'NOTIFIED' && (
                        <span style={{ fontSize: '12px', color: '#7f8c8d' }}>
                          Claim under 'Notifications' tab!
                        </span>
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </>
      )}
    </div>
  );
}

export default MyBorrows;
